import './../css/about_me.scss'
const AboutMe = () => {
    return (
      <div className="home">
        <h1>About Me</h1>
        <p> I am Fabian and I am interested in learning new skills from AI, Crypto, Cloud Computing to Full Stack Development </p>
        <p> This is a place where I will display mini project that I worked on during my free time </p>
        <p> All that you are seeing here is still work in progress! </p>
        
        <h2> Tech Involved </h2>
        <p> HTML </p>
        <p> SCSS </p>
        <p> JavaScript </p>
        <p> react.js </p>
        <p> My Tech Stack is not limited to this list! </p>
        <p> Thank you for visiting!</p>
      </div>
    );
  }
   
  export default AboutMe;
